class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        graph = [[] for _ in range(n)]
        restricted = set()
        for x, y in restrictions:
            restricted.add(frozenset([x, y]))
        result = []
        for u, v in requests:
            if frozenset([u, v]) in restricted:
                result.append(False)
            else:
                visited = set()
                stack = [u]
                while stack:
                    node = stack.pop()
                    if node == v:
                        result.append(True)
                        break
                    visited.add(node)
                    for neighbor in graph[node]:
                        if neighbor not in visited:
                            stack.append(neighbor)
                else:
                    result.append(False)
                if result[-1]:
                    graph[u].append(v)
                    graph[v].append(u)
        return result
```

